(function() {
  'use strict';

  if (window.__baMovieSearchActive) return;
  window.__baMovieSearchActive = true;

  // ===== CONFIGURATION =====
  var OMDB_API_KEY = 'REPLACE_WITH_YOUR_OMDB_API_KEY'; // Get your free key at https://www.omdbapi.com/apikey.aspx
  var OMDB_BASE = 'https://www.omdbapi.com/?apikey=' + OMDB_API_KEY + '&';
  var POSTER_BASE = 'https://img.omdbapi.com/?apikey=' + OMDB_API_KEY + '&';
  // =========================

  // --- Inject styles ---
  var style = document.createElement('style');
  style.textContent = `
    #ba-ms-toggle {
      position: fixed; bottom: 20px; right: 20px; z-index: 2147483646;
      width: 48px; height: 48px; border-radius: 50%; border: none;
      background: #f5c518; color: #000; font-size: 22px; cursor: pointer;
      box-shadow: 0 4px 16px rgba(0,0,0,0.3); display: flex; align-items: center;
      justify-content: center; transition: transform 0.2s, box-shadow 0.2s;
      font-family: Arial, sans-serif;
    }
    #ba-ms-toggle:hover { transform: scale(1.1); box-shadow: 0 6px 24px rgba(0,0,0,0.4); }
    #ba-ms-panel {
      position: fixed; bottom: 80px; right: 20px; z-index: 2147483647;
      width: 420px; max-height: 600px; background: #1a1a2e; color: #e0e0e0;
      border-radius: 12px; box-shadow: 0 8px 32px rgba(0,0,0,0.5);
      font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
      display: none; flex-direction: column; overflow: hidden;
      border: 1px solid #2a2a4a;
    }
    #ba-ms-panel.ba-ms-open { display: flex; }
    .ba-ms-header {
      padding: 14px 16px 10px; background: #16213e; border-bottom: 1px solid #2a2a4a;
      display: flex; align-items: center; gap: 10px; flex-shrink: 0;
    }
    .ba-ms-header .ba-ms-logo { color: #f5c518; font-weight: 800; font-size: 16px; }
    .ba-ms-header .ba-ms-close {
      margin-left: auto; background: none; border: none; color: #888;
      font-size: 20px; cursor: pointer; padding: 0 4px; line-height: 1;
    }
    .ba-ms-header .ba-ms-close:hover { color: #fff; }
    .ba-ms-search-row {
      padding: 10px 16px; display: flex; gap: 8px; flex-shrink: 0;
      background: #1a1a2e;
    }
    .ba-ms-search-row input[type='text'] {
      flex: 1; padding: 8px 12px; border-radius: 8px; border: 1px solid #333;
      background: #0f0f23; color: #e0e0e0; font-size: 14px; outline: none;
    }
    .ba-ms-search-row input[type='text']:focus { border-color: #f5c518; }
    .ba-ms-search-row button {
      padding: 8px 14px; border-radius: 8px; border: none;
      background: #f5c518; color: #000; font-weight: 700; font-size: 13px;
      cursor: pointer; white-space: nowrap;
    }
    .ba-ms-search-row button:hover { background: #e0b000; }
    .ba-ms-filters {
      padding: 0 16px 10px; display: flex; gap: 8px; flex-shrink: 0;
    }
    .ba-ms-filters select, .ba-ms-filters input[type='number'] {
      padding: 5px 8px; border-radius: 6px; border: 1px solid #333;
      background: #0f0f23; color: #e0e0e0; font-size: 12px; outline: none;
    }
    .ba-ms-filters select:focus, .ba-ms-filters input[type='number']:focus { border-color: #f5c518; }
    .ba-ms-filters label { font-size: 11px; color: #888; display: flex; flex-direction: column; gap: 2px; }
    .ba-ms-body {
      flex: 1; overflow-y: auto; padding: 0 16px 12px; min-height: 100px;
    }
    .ba-ms-body::-webkit-scrollbar { width: 6px; }
    .ba-ms-body::-webkit-scrollbar-thumb { background: #333; border-radius: 3px; }
    .ba-ms-status { text-align: center; padding: 30px 0; color: #666; font-size: 13px; }
    .ba-ms-status.ba-ms-error { color: #ef4444; }

    /* Search results grid */
    .ba-ms-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; padding-top: 8px; }
    .ba-ms-card {
      background: #16213e; border-radius: 8px; overflow: hidden; cursor: pointer;
      border: 1px solid transparent; transition: border-color 0.15s, transform 0.15s;
    }
    .ba-ms-card:hover { border-color: #f5c518; transform: translateY(-2px); }
    .ba-ms-card-poster {
      width: 100%; aspect-ratio: 2/3; object-fit: cover; background: #0f0f23; display: block;
    }
    .ba-ms-card-info { padding: 8px; }
    .ba-ms-card-title {
      font-size: 12px; font-weight: 600; color: #fff;
      overflow: hidden; text-overflow: ellipsis; white-space: nowrap;
    }
    .ba-ms-card-year { font-size: 11px; color: #888; }
    .ba-ms-card-type {
      font-size: 10px; color: #f5c518; text-transform: uppercase; font-weight: 700;
    }
    .ba-ms-pagination {
      display: flex; justify-content: center; gap: 8px; padding: 12px 0 4px;
    }
    .ba-ms-pagination button {
      padding: 5px 12px; border-radius: 6px; border: 1px solid #333;
      background: #0f0f23; color: #e0e0e0; font-size: 12px; cursor: pointer;
    }
    .ba-ms-pagination button:hover { border-color: #f5c518; }
    .ba-ms-pagination button:disabled { opacity: 0.3; cursor: default; }
    .ba-ms-pagination span { font-size: 12px; color: #888; line-height: 28px; }

    /* Detail view */
    .ba-ms-detail { padding-top: 8px; }
    .ba-ms-detail-back {
      background: none; border: none; color: #f5c518; font-size: 13px;
      cursor: pointer; padding: 0 0 10px; font-weight: 600;
    }
    .ba-ms-detail-back:hover { text-decoration: underline; }
    .ba-ms-detail-top { display: flex; gap: 14px; }
    .ba-ms-detail-poster {
      width: 140px; min-width: 140px; border-radius: 8px; object-fit: cover;
      background: #0f0f23;
    }
    .ba-ms-detail-meta { flex: 1; }
    .ba-ms-detail-title { font-size: 18px; font-weight: 700; color: #fff; margin: 0 0 4px; line-height: 1.2; }
    .ba-ms-detail-sub { font-size: 12px; color: #888; margin-bottom: 8px; }
    .ba-ms-detail-genre { font-size: 11px; color: #f5c518; margin-bottom: 10px; }
    .ba-ms-ratings { display: flex; flex-wrap: wrap; gap: 6px; margin-bottom: 10px; }
    .ba-ms-rating-badge {
      display: inline-flex; align-items: center; gap: 4px;
      padding: 3px 8px; border-radius: 4px; font-size: 11px; font-weight: 700;
    }
    .ba-ms-rating-imdb { background: #f5c518; color: #000; }
    .ba-ms-rating-rt { background: #fa320a; color: #fff; }
    .ba-ms-rating-mc { background: #6c3; color: #fff; }
    .ba-ms-detail-section { margin-top: 12px; }
    .ba-ms-detail-section h4 {
      font-size: 11px; color: #888; text-transform: uppercase; margin: 0 0 4px;
      letter-spacing: 0.5px;
    }
    .ba-ms-detail-section p {
      font-size: 13px; color: #ccc; line-height: 1.5; margin: 0;
    }
    .ba-ms-detail-row {
      display: flex; gap: 10px; flex-wrap: wrap; margin-top: 10px;
    }
    .ba-ms-detail-item { font-size: 12px; }
    .ba-ms-detail-item .ba-ms-label { color: #888; }
    .ba-ms-detail-item .ba-ms-value { color: #e0e0e0; font-weight: 500; }
    .ba-ms-imdb-link {
      display: inline-flex; align-items: center; gap: 4px;
      margin-top: 10px; padding: 6px 12px; border-radius: 6px;
      background: #f5c518; color: #000; font-size: 12px; font-weight: 700;
      text-decoration: none;
    }
    .ba-ms-imdb-link:hover { background: #e0b000; }
  `;
  document.head.appendChild(style);

  // --- State ---
  var state = { query: '', type: '', year: '', page: 1, totalResults: 0, results: [], detail: null };

  // --- Build DOM ---
  var toggle = document.createElement('button');
  toggle.id = 'ba-ms-toggle';
  toggle.innerHTML = '\uD83C\uDFAC';
  toggle.title = 'Open Movie Search';
  document.body.appendChild(toggle);

  var panel = document.createElement('div');
  panel.id = 'ba-ms-panel';
  panel.innerHTML = [
    '<div class="ba-ms-header">',
    '  <span class="ba-ms-logo">\uD83C\uDFAC Open Movie Search</span>',
    '  <button class="ba-ms-close" title="Close">&times;</button>',
    '</div>',
    '<div class="ba-ms-search-row">',
    '  <input type="text" id="ba-ms-input" placeholder="Search movies, series, anime..." />',
    '  <button id="ba-ms-search-btn">Search</button>',
    '</div>',
    '<div class="ba-ms-filters">',
    '  <label>Type<select id="ba-ms-type"><option value="">All</option><option value="movie">Movie</option><option value="series">Series</option><option value="episode">Episode</option></select></label>',
    '  <label>Year<input type="number" id="ba-ms-year" min="1900" max="2099" placeholder="Any" style="width:70px" /></label>',
    '</div>',
    '<div class="ba-ms-body" id="ba-ms-body">',
    '  <div class="ba-ms-status">Search for a movie or series to get started.</div>',
    '</div>'
  ].join('\n');
  document.body.appendChild(panel);

  var inputEl = panel.querySelector('#ba-ms-input');
  var searchBtn = panel.querySelector('#ba-ms-search-btn');
  var typeEl = panel.querySelector('#ba-ms-type');
  var yearEl = panel.querySelector('#ba-ms-year');
  var bodyEl = panel.querySelector('#ba-ms-body');
  var closeBtn = panel.querySelector('.ba-ms-close');

  // --- Toggle ---
  toggle.addEventListener('click', function() {
    panel.classList.toggle('ba-ms-open');
    if (panel.classList.contains('ba-ms-open')) inputEl.focus();
  });
  closeBtn.addEventListener('click', function() {
    panel.classList.remove('ba-ms-open');
  });

  // --- API helpers ---
  async function searchMovies(query, type, year, page) {
    var url = OMDB_BASE + 's=' + encodeURIComponent(query);
    if (type) url += '&type=' + type;
    if (year) url += '&y=' + year;
    url += '&page=' + page + '&r=json';
    var resp = await fetch(url);
    return resp.json();
  }

  async function getDetail(imdbID) {
    var url = OMDB_BASE + 'i=' + encodeURIComponent(imdbID) + '&plot=full&r=json';
    var resp = await fetch(url);
    return resp.json();
  }

  function posterUrl(src) {
    if (!src || src === 'N/A') return '';
    return src;
  }

  // --- Render helpers ---
  function renderStatus(msg, isError) {
    bodyEl.innerHTML = '<div class="ba-ms-status' + (isError ? ' ba-ms-error' : '') + '">' + msg + '</div>';
  }

  function renderResults() {
    if (state.results.length === 0) {
      renderStatus('No results found.');
      return;
    }

    var totalPages = Math.ceil(state.totalResults / 10);
    var html = '<div class="ba-ms-grid">';

    state.results.forEach(function(item) {
      var poster = posterUrl(item.Poster);
      html += '<div class="ba-ms-card" data-imdbid="' + item.imdbID + '">';
      if (poster) {
        html += '<img class="ba-ms-card-poster" src="' + poster + '" alt="" loading="lazy" onerror="this.style.display=\'none\'" />';
      } else {
        html += '<div class="ba-ms-card-poster" style="display:flex;align-items:center;justify-content:center;color:#444;font-size:32px">\uD83C\uDFAC</div>';
      }
      html += '<div class="ba-ms-card-info">';
      html += '<div class="ba-ms-card-title" title="' + item.Title.replace(/"/g, '&quot;') + '">' + item.Title + '</div>';
      html += '<div class="ba-ms-card-year">' + item.Year + '</div>';
      html += '<div class="ba-ms-card-type">' + item.Type + '</div>';
      html += '</div></div>';
    });

    html += '</div>';

    if (totalPages > 1) {
      html += '<div class="ba-ms-pagination">';
      html += '<button id="ba-ms-prev"' + (state.page <= 1 ? ' disabled' : '') + '>\u2190 Prev</button>';
      html += '<span>' + state.page + ' / ' + totalPages + ' (' + state.totalResults + ' results)</span>';
      html += '<button id="ba-ms-next"' + (state.page >= totalPages ? ' disabled' : '') + '>Next \u2192</button>';
      html += '</div>';
    }

    bodyEl.innerHTML = html;

    // Card clicks
    bodyEl.querySelectorAll('.ba-ms-card').forEach(function(card) {
      card.addEventListener('click', function() {
        loadDetail(card.getAttribute('data-imdbid'));
      });
    });

    // Pagination
    var prevBtn = bodyEl.querySelector('#ba-ms-prev');
    var nextBtn = bodyEl.querySelector('#ba-ms-next');
    if (prevBtn) prevBtn.addEventListener('click', function() { if (state.page > 1) { state.page--; doSearch(); } });
    if (nextBtn) nextBtn.addEventListener('click', function() { state.page++; doSearch(); });
  }

  function renderDetail(data) {
    var poster = posterUrl(data.Poster);
    var html = '<div class="ba-ms-detail">';
    html += '<button class="ba-ms-detail-back">\u2190 Back to results</button>';
    html += '<div class="ba-ms-detail-top">';

    if (poster) {
      html += '<img class="ba-ms-detail-poster" src="' + poster + '" alt="" onerror="this.style.display=\'none\'" />';
    }

    html += '<div class="ba-ms-detail-meta">';
    html += '<h3 class="ba-ms-detail-title">' + data.Title + '</h3>';
    html += '<div class="ba-ms-detail-sub">' + [data.Year, data.Rated, data.Runtime, data.Type].filter(function(v) { return v && v !== 'N/A'; }).join(' \u2022 ') + '</div>';

    if (data.Genre && data.Genre !== 'N/A') {
      html += '<div class="ba-ms-detail-genre">' + data.Genre + '</div>';
    }

    // Ratings
    html += '<div class="ba-ms-ratings">';
    if (data.imdbRating && data.imdbRating !== 'N/A') {
      html += '<span class="ba-ms-rating-badge ba-ms-rating-imdb">\u2B50 ' + data.imdbRating + '/10</span>';
    }
    if (data.Ratings) {
      data.Ratings.forEach(function(r) {
        if (r.Source === 'Rotten Tomatoes') {
          html += '<span class="ba-ms-rating-badge ba-ms-rating-rt">\uD83C\uDF45 ' + r.Value + '</span>';
        }
        if (r.Source === 'Metacritic') {
          html += '<span class="ba-ms-rating-badge ba-ms-rating-mc">MC ' + r.Value + '</span>';
        }
      });
    }
    html += '</div>';

    if (data.imdbID) {
      html += '<a class="ba-ms-imdb-link" href="https://www.imdb.com/title/' + data.imdbID + '/" target="_blank" rel="noopener">View on IMDB \u2197</a>';
    }

    html += '</div></div>'; // close meta + top

    // Plot
    if (data.Plot && data.Plot !== 'N/A') {
      html += '<div class="ba-ms-detail-section"><h4>Plot</h4><p>' + data.Plot + '</p></div>';
    }

    // Info rows
    var fields = [
      ['Director', data.Director],
      ['Writer', data.Writer],
      ['Actors', data.Actors],
      ['Language', data.Language],
      ['Country', data.Country],
      ['Awards', data.Awards],
      ['Box Office', data.BoxOffice],
      ['IMDB Votes', data.imdbVotes]
    ];

    html += '<div class="ba-ms-detail-row">';
    fields.forEach(function(f) {
      if (f[1] && f[1] !== 'N/A') {
        html += '<div class="ba-ms-detail-item"><span class="ba-ms-label">' + f[0] + ': </span><span class="ba-ms-value">' + f[1] + '</span></div>';
      }
    });
    html += '</div>';

    html += '</div>';
    bodyEl.innerHTML = html;

    bodyEl.querySelector('.ba-ms-detail-back').addEventListener('click', function() {
      state.detail = null;
      renderResults();
    });
  }

  // --- Actions ---
  async function doSearch() {
    var query = state.query.trim();
    if (!query) { renderStatus('Enter a title to search.'); return; }

    if (OMDB_API_KEY === 'REPLACE_WITH_YOUR_OMDB_API_KEY') {
      renderStatus('Please set your OMDb API key in the script. Get a free key at omdbapi.com/apikey.aspx', true);
      return;
    }

    renderStatus('Searching...');

    try {
      var data = await searchMovies(query, state.type, state.year, state.page);

      if (data.Response === 'True') {
        state.results = data.Search || [];
        state.totalResults = parseInt(data.totalResults, 10) || 0;
        renderResults();
      } else {
        state.results = [];
        state.totalResults = 0;
        renderStatus(data.Error || 'No results found.');
      }
    } catch (err) {
      renderStatus('Network error: ' + err.message, true);
    }
  }

  async function loadDetail(imdbID) {
    renderStatus('Loading details...');
    try {
      var data = await getDetail(imdbID);
      if (data.Response === 'True') {
        state.detail = data;
        renderDetail(data);
      } else {
        renderStatus(data.Error || 'Could not load details.', true);
      }
    } catch (err) {
      renderStatus('Network error: ' + err.message, true);
    }
  }

  // --- Event listeners ---
  searchBtn.addEventListener('click', function() {
    state.query = inputEl.value;
    state.type = typeEl.value;
    state.year = yearEl.value;
    state.page = 1;
    doSearch();
  });

  inputEl.addEventListener('keydown', function(e) {
    if (e.key === 'Enter') {
      state.query = inputEl.value;
      state.type = typeEl.value;
      state.year = yearEl.value;
      state.page = 1;
      doSearch();
    }
  });

  // Close on Escape
  document.addEventListener('keydown', function(e) {
    if (e.key === 'Escape' && panel.classList.contains('ba-ms-open')) {
      panel.classList.remove('ba-ms-open');
    }
  });

  console.log('[Open Movie Search] Active — click the \uD83C\uDFAC button to search movies.');
  if (OMDB_API_KEY === 'REPLACE_WITH_YOUR_OMDB_API_KEY') {
    console.warn('[Open Movie Search] Please replace the API key with your own from https://www.omdbapi.com/apikey.aspx');
  }
})();
